// src/Login.js
import React from 'react';
import './Login.css';

function Login() {
    return (
        <div className="containerLogin">
            <h1 className="h1Login">Entrar</h1>
            <form action="dashboard.html" method="post" className="formLogin">
                <div className="formGroupLogin">
                    <input type="email" id="email" name="email" placeholder="E-mail" required className="inputLogin" />
                </div>
                
                <div className="formGroupLogin">
                    <input type="password" id="senha" name="senha" placeholder="Senha" required className="inputLogin" />
                </div>

                <div className="formGroupLogin">
                    <button type="submit" className="buttonLogin">Entrar</button>
                </div>

                <div className="linksLogin">
                    <a href="#">Esqueceu a senha?</a>
                    <p>Não tem uma conta? <a href="register.html">Cadastre-se</a></p>
                </div>
            </form>
        </div>
    );
}

export default Login;
